// ===================================================
// WF-13: 4등급 등급 심사 로직
// BLOOM(25%) → GARDEN(20%) → ATELIER(15%) → AMBASSADOR(10%)
//
// 승급 기준:
//   BLOOM → GARDEN:       완료 10건 + 평점 4.0↑
//   GARDEN → ATELIER:     완료 30건 + 평점 4.3↑
//   ATELIER → AMBASSADOR: 완료 50건 (추천 기준은 추후)
//
// 저장 등급은 legacy 옵션(SILVER/GOLD/PLATINUM)으로 유지한다.
// 현재 표시 등급 판정은 commission_rate를 우선 기준으로 삼아
// AMBASSADOR(10%)가 PLATINUM 저장값으로 남아도 재승급 루프를 막는다.
// ===================================================

const partnersData = $('Get Partners').first().json;
const settlementsData = $('Get Settlements').first().json;
const reviewsData = $input.first().json;

const partners = partnersData.list || [];
const settlements = settlementsData.list || [];
const reviews = reviewsData.list || [];

if (partners.length === 0) {
  return [{ json: { totalReviewed: 0, totalChanges: 0, changes: [], executedAt: new Date().toISOString() } }];
}

// --- 파트너별 완료 건수 집계 ---
const completedMap = {};
for (const s of settlements) {
  const code = s.partner_code;
  if (!code) continue;
  completedMap[code] = (completedMap[code] || 0) + 1;
}

// --- 파트너별 평균 평점 집계 ---
const ratingMap = {};
for (const r of reviews) {
  const code = r.partner_code;
  const rating = Number(r.rating);
  if (!code || isNaN(rating)) continue;
  if (!ratingMap[code]) ratingMap[code] = { sum: 0, count: 0 };
  ratingMap[code].sum += rating;
  ratingMap[code].count += 1;
}

// --- 등급 체계 ---
const GRADE_ORDER = ['BLOOM', 'GARDEN', 'ATELIER', 'AMBASSADOR'];
const COMMISSION_RATES = { BLOOM: 0.25, GARDEN: 0.20, ATELIER: 0.15, AMBASSADOR: 0.10 };
const STORAGE_GRADE_MAP = { BLOOM: 'SILVER', GARDEN: 'GOLD', ATELIER: 'PLATINUM', AMBASSADOR: 'PLATINUM' };
const GRADE_ALIAS = { SILVER: 'BLOOM', GOLD: 'GARDEN', PLATINUM: 'ATELIER' };
const RATE_ALIAS = { 25: 'BLOOM', 20: 'GARDEN', 15: 'ATELIER', 10: 'AMBASSADOR' };

function normalizePercent(value) {
  const num = Number(value) || 0;
  if (!num) return 0;
  return num > 0 && num < 1 ? Math.round(num * 100) : Math.round(num);
}

// --- 등급 판정 ---
const changes = [];

for (const p of partners) {
  const rawGrade = (p.grade || 'SILVER').toUpperCase();
  const rateGrade = RATE_ALIAS[normalizePercent(p.commission_rate)];
  const currentGrade = rateGrade || GRADE_ALIAS[rawGrade] || rawGrade;
  const currentIdx = GRADE_ORDER.indexOf(currentGrade);
  const code = p.partner_code;

  const completedCount = completedMap[code] || 0;
  const ri = ratingMap[code];
  const avgRating = ri ? Math.round((ri.sum / ri.count) * 100) / 100 : 0;

  let nextGrade = currentGrade;
  let nextIdx = currentIdx;

  // BLOOM → GARDEN
  if (currentIdx < 1 && completedCount >= 10 && avgRating >= 4.0) {
    nextGrade = 'GARDEN'; nextIdx = 1;
  }
  // GARDEN → ATELIER
  if (nextIdx < 2 && completedCount >= 30 && avgRating >= 4.3) {
    nextGrade = 'ATELIER'; nextIdx = 2;
  }
  // ATELIER → AMBASSADOR
  if (nextIdx < 3 && completedCount >= 50) {
    nextGrade = 'AMBASSADOR'; nextIdx = 3;
  }

  if (nextGrade !== currentGrade) {
    changes.push({
      recordId: p.Id,
      partnerCode: code,
      partnerName: p.partner_name,
      memberId: p.member_id,
      oldGrade: currentGrade,
      newGrade: nextGrade,
      newStorageGrade: STORAGE_GRADE_MAP[nextGrade] || 'PLATINUM',
      newCommissionRate: COMMISSION_RATES[nextGrade],
      completedCount,
      avgRating
    });
  }
}

return [{ json: {
  totalReviewed: partners.length,
  totalChanges: changes.length,
  changes,
  executedAt: new Date().toISOString()
} }];

// 변경 건 각각을 아이템으로 분리 (PATCH용)
const data = $input.first().json;
const changes = data.changes || [];
return changes.map(c => ({ json: { ...c, _summary: data } }));

// 등급 변경 요약 텔레그램 메시지
const firstItem = items[0].json;
const summary = firstItem._summary || $('Has Changes?').first().json || {};
const changes = summary.changes || [];

let lines = '';
for (const c of changes) {
  lines += '\n• ' + c.partnerCode + ' (' + c.partnerName + '): '
    + c.oldGrade + ' → ' + c.newGrade
    + ' [완료 ' + c.completedCount + '건, ★' + c.avgRating + ']';
}

const msg = '⭐ 파트너 등급 자동 심사 완료\n\n'
  + '실행: ' + summary.executedAt + '\n'
  + '검토: ' + summary.totalReviewed + '명\n'
  + '등급 변경: ' + summary.totalChanges + '건'
  + lines;

return [{ json: { message: msg } }];

// 변경 없음 메시지
const data = $input.first().json;
const msg = '⭐ 파트너 등급 자동 심사 완료\n\n'
  + '실행: ' + data.executedAt + '\n'
  + '검토: ' + data.totalReviewed + '명\n'
  + '등급 변경: 0건 (변경 없음)';
return [{ json: { message: msg } }];
